# Extended Table 1: Taylor expansion of the magnetic field (constant h)

# Coefficients of the monomials x^p y^q in B_x, B_y, B_s, for total
# degree p+q <= 12, assuming the curvature h is constant (h' = 0).
# Notation: a(n,m) = d^m a_n/ds^m, b(n,m) = d^m b_n/ds^m,
# bs(m) = d^m b_s/ds^m.

## x^0 y^0

Bx_coef[0, 0] = a(1,0)

By_coef[0, 0] = b(1,0)

Bs_coef[0, 0] = bs(0)

## x^1 y^0

Bx_coef[1, 0] = a(2,0)

By_coef[1, 0] = b(2,0)

Bs_coef[1, 0] = a(1,1) - h*bs(0)

## x^2 y^0

Bx_coef[2, 0] = (1//2)*a(3,0)

By_coef[2, 0] = (1//2)*b(3,0)

Bs_coef[2, 0] = (1//2)*a(2,1) - h*a(1,1) + (h^2)*bs(0)

## x^3 y^0

Bx_coef[3, 0] = (1//6)*a(4,0)

By_coef[3, 0] = (1//6)*b(4,0)

Bs_coef[3, 0] = (1//6)*a(3,1) - (1//2)*h*a(2,1) + (h^2)*a(1,1) - (h^3)*bs(0)

## x^4 y^0

Bx_coef[4, 0] = (1//24)*a(5,0)

By_coef[4, 0] = (1//24)*b(5,0)

Bs_coef[4, 0] = (1//24)*a(4,1) - (1//6)*h*a(3,1) + (1//2)*(h^2)*a(2,1) - (h^3)*a(1,1) + (h^4)*bs(0)

## x^5 y^0

Bx_coef[5, 0] = (1//120)*a(6,0)

By_coef[5, 0] = (1//120)*b(6,0)

Bs_coef[5, 0] = (1//120)*a(5,1) - (1//24)*h*a(4,1) + (1//6)*(h^2)*a(3,1) - (1//2)*(h^3)*a(2,1) + (h^4)*a(1,1) - (h^5)*bs(0)

## x^6 y^0

Bx_coef[6, 0] = (1//720)*a(7,0)

By_coef[6, 0] = (1//720)*b(7,0)

Bs_coef[6, 0] = (1//720)*a(6,1) - (1//120)*h*a(5,1) + (1//24)*(h^2)*a(4,1) - (1//6)*(h^3)*a(3,1) + (1//2)*(h^4)*a(2,1) - (h^5)*a(1,1) + (h^6)*bs(0)

## x^7 y^0

Bx_coef[7, 0] = (1//5040)*a(8,0)

By_coef[7, 0] = (1//5040)*b(8,0)

Bs_coef[7, 0] = (1//5040)*a(7,1) - (1//720)*h*a(6,1) + (1//120)*(h^2)*a(5,1) - (1//24)*(h^3)*a(4,1) + (1//6)*(h^4)*a(3,1) - (1//2)*(h^5)*a(2,1) + (h^6)*a(1,1) - (h^7)*bs(0)

## x^8 y^0

Bx_coef[8, 0] = (1//40320)*a(9,0)

By_coef[8, 0] = (1//40320)*b(9,0)

Bs_coef[8, 0] = (1//40320)*a(8,1) - (1//5040)*h*a(7,1) + (1//720)*(h^2)*a(6,1) - (1//120)*(h^3)*a(5,1) + (1//24)*(h^4)*a(4,1) - (1//6)*(h^5)*a(3,1) + (1//2)*(h^6)*a(2,1) - (h^7)*a(1,1) + (h^8)*bs(0)

## x^9 y^0

Bx_coef[9, 0] = (1//362880)*a(10,0)

By_coef[9, 0] = (1//362880)*b(10,0)

Bs_coef[9, 0] = (1//362880)*a(9,1) - (1//40320)*h*a(8,1) + (1//5040)*(h^2)*a(7,1) - (1//720)*(h^3)*a(6,1) + (1//120)*(h^4)*a(5,1) - (1//24)*(h^5)*a(4,1) + (1//6)*(h^6)*a(3,1) - (1//2)*(h^7)*a(2,1) + (h^8)*a(1,1) - (h^9)*bs(0)

## x^10 y^0

Bx_coef[10, 0] = (1//3628800)*a(11,0)

By_coef[10, 0] = (1//3628800)*b(11,0)

Bs_coef[10, 0] = (1//3628800)*a(10,1) - (1//362880)*h*a(9,1) + (1//40320)*(h^2)*a(8,1) - (1//5040)*(h^3)*a(7,1) + (1//720)*(h^4)*a(6,1) - (1//120)*(h^5)*a(5,1) + (1//24)*(h^6)*a(4,1) - (1//6)*(h^7)*a(3,1) + (1//2)*(h^8)*a(2,1) - (h^9)*a(1,1) + (h^10)*bs(0)

## x^11 y^0

Bx_coef[11, 0] = (1//39916800)*a(12,0)

By_coef[11, 0] = (1//39916800)*b(12,0)

Bs_coef[11, 0] = (1//39916800)*a(11,1) - (1//3628800)*h*a(10,1) + (1//362880)*(h^2)*a(9,1) - (1//40320)*(h^3)*a(8,1) + (1//5040)*(h^4)*a(7,1) - (1//720)*(h^5)*a(6,1) + (1//120)*(h^6)*a(5,1) - (1//24)*(h^7)*a(4,1) + (1//6)*(h^8)*a(3,1) - (1//2)*(h^9)*a(2,1) + (h^10)*a(1,1) - (h^11)*bs(0)

## x^12 y^0

Bx_coef[12, 0] = (1//479001600)*a(13,0)

By_coef[12, 0] = (1//479001600)*b(13,0)

Bs_coef[12, 0] = (1//479001600)*a(12,1) - (1//39916800)*h*a(11,1) + (1//3628800)*(h^2)*a(10,1) - (1//362880)*(h^3)*a(9,1) + (1//40320)*(h^4)*a(8,1) - (1//5040)*(h^5)*a(7,1) + (1//720)*(h^6)*a(6,1) - (1//120)*(h^7)*a(5,1) + (1//24)*(h^8)*a(4,1) - (1//6)*(h^9)*a(3,1) + (1//2)*(h^10)*a(2,1) - (h^11)*a(1,1) + (h^12)*bs(0)

## x^0 y^1

Bx_coef[0, 1] = b(2,0)

By_coef[0, 1] = -a(2,0) - bs(1) - h*a(1,0)

Bs_coef[0, 1] = b(1,1)

## x^1 y^1

Bx_coef[1, 1] = b(3,0)

By_coef[1, 1] = -a(1,2) - a(3,0) - h*a(2,0) + 2h*bs(1) + (h^2)*a(1,0)

Bs_coef[1, 1] = b(2,1) - h*b(1,1)

## x^2 y^1

Bx_coef[2, 1] = (1//2)*b(4,0)

By_coef[2, 1] = -(1//2)*a(4,0) - (1//2)*a(2,2) + 2h*a(1,2) - (1//2)*h*a(3,0) + (h^2)*a(2,0) - 3(h^2)*bs(1) - (h^3)*a(1,0)

Bs_coef[2, 1] = (1//2)*b(3,1) - h*b(2,1) + (h^2)*b(1,1)

## x^3 y^1

Bx_coef[3, 1] = (1//6)*b(5,0)

By_coef[3, 1] = -(1//6)*a(3,2) - (1//6)*a(5,0) - (1//6)*h*a(4,0) + h*a(2,2) - 3(h^2)*a(1,2) + (1//2)*(h^2)*a(3,0) - (h^3)*a(2,0) + 4(h^3)*bs(1) + (h^4)*a(1,0)

Bs_coef[3, 1] = (1//6)*b(4,1) - (1//2)*h*b(3,1) + (h^2)*b(2,1) - (h^3)*b(1,1)

## x^4 y^1

Bx_coef[4, 1] = (1//24)*b(6,0)

By_coef[4, 1] = -(1//24)*a(4,2) - (1//24)*a(6,0) + (1//3)*h*a(3,2) - (1//24)*h*a(5,0) + (1//6)*(h^2)*a(4,0) - (3//2)*(h^2)*a(2,2) + 4(h^3)*a(1,2) - (1//2)*(h^3)*a(3,0) + (h^4)*a(2,0) - 5(h^4)*bs(1) - (h^5)*a(1,0)

Bs_coef[4, 1] = (1//24)*b(5,1) - (1//6)*h*b(4,1) + (1//2)*(h^2)*b(3,1) - (h^3)*b(2,1) + (h^4)*b(1,1)

## x^5 y^1

Bx_coef[5, 1] = (1//120)*b(7,0)

By_coef[5, 1] = -(1//120)*a(7,0) - (1//120)*a(5,2) + (1//12)*h*a(4,2) - (1//120)*h*a(6,0) - (1//2)*(h^2)*a(3,2) + (1//24)*(h^2)*a(5,0) - (1//6)*(h^3)*a(4,0) + (2//1)*(h^3)*a(2,2) - 5(h^4)*a(1,2) + (1//2)*(h^4)*a(3,0) - (h^5)*a(2,0) + 6(h^5)*bs(1) + (h^6)*a(1,0)

Bs_coef[5, 1] = (1//120)*b(6,1) - (1//24)*h*b(5,1) + (1//6)*(h^2)*b(4,1) - (1//2)*(h^3)*b(3,1) + (h^4)*b(2,1) - (h^5)*b(1,1)

## x^6 y^1

Bx_coef[6, 1] = (1//720)*b(8,0)

By_coef[6, 1] = -(1//720)*a(8,0) - (1//720)*a(6,2) - (1//720)*h*a(7,0) + (1//60)*h*a(5,2) - (1//8)*(h^2)*a(4,2) + (1//120)*(h^2)*a(6,0) + (2//3)*(h^3)*a(3,2) - (1//24)*(h^3)*a(5,0) + (1//6)*(h^4)*a(4,0) - (5//2)*(h^4)*a(2,2) + 6(h^5)*a(1,2) - (1//2)*(h^5)*a(3,0) + (h^6)*a(2,0) - 7(h^6)*bs(1) - (h^7)*a(1,0)

Bs_coef[6, 1] = (1//720)*b(7,1) - (1//120)*h*b(6,1) + (1//24)*(h^2)*b(5,1) - (1//6)*(h^3)*b(4,1) + (1//2)*(h^4)*b(3,1) - (h^5)*b(2,1) + (h^6)*b(1,1)

## x^7 y^1

Bx_coef[7, 1] = (1//5040)*b(9,0)

By_coef[7, 1] = -(1//5040)*a(9,0) - (1//5040)*a(7,2) - (1//5040)*h*a(8,0) + (1//360)*h*a(6,2) + (1//720)*(h^2)*a(7,0) - (1//40)*(h^2)*a(5,2) + (1//6)*(h^3)*a(4,2) - (1//120)*(h^3)*a(6,0) - (5//6)*(h^4)*a(3,2) + (1//24)*(h^4)*a(5,0) - (1//6)*(h^5)*a(4,0) + (3//1)*(h^5)*a(2,2) - 7(h^6)*a(1,2) + (1//2)*(h^6)*a(3,0) - (h^7)*a(2,0) + 8(h^7)*bs(1) + (h^8)*a(1,0)

Bs_coef[7, 1] = (1//5040)*b(8,1) - (1//720)*h*b(7,1) + (1//120)*(h^2)*b(6,1) - (1//24)*(h^3)*b(5,1) + (1//6)*(h^4)*b(4,1) - (1//2)*(h^5)*b(3,1) + (h^6)*b(2,1) - (h^7)*b(1,1)

## x^8 y^1

Bx_coef[8, 1] = (1//40320)*b(10,0)

By_coef[8, 1] = -(1//40320)*a(8,2) - (1//40320)*a(10,0) - (1//40320)*h*a(9,0) + (1//2520)*h*a(7,2) + (1//5040)*(h^2)*a(8,0) - (1//240)*(h^2)*a(6,2) - (1//720)*(h^3)*a(7,0) + (1//30)*(h^3)*a(5,2) - (5//24)*(h^4)*a(4,2) + (1//120)*(h^4)*a(6,0) + (h^5)*a(3,2) - (1//24)*(h^5)*a(5,0) + (1//6)*(h^6)*a(4,0) - (7//2)*(h^6)*a(2,2) + 8(h^7)*a(1,2) - (1//2)*(h^7)*a(3,0) + (h^8)*a(2,0) - 9(h^8)*bs(1) - (h^9)*a(1,0)

Bs_coef[8, 1] = (1//40320)*b(9,1) - (1//5040)*h*b(8,1) + (1//720)*(h^2)*b(7,1) - (1//120)*(h^3)*b(6,1) + (1//24)*(h^4)*b(5,1) - (1//6)*(h^5)*b(4,1) + (1//2)*(h^6)*b(3,1) - (h^7)*b(2,1) + (h^8)*b(1,1)

## x^9 y^1

Bx_coef[9, 1] = (1//362880)*b(11,0)

By_coef[9, 1] = -(1//362880)*a(11,0) - (1//362880)*a(9,2) + (1//20160)*h*a(8,2) - (1//362880)*h*a(10,0) + (1//40320)*(h^2)*a(9,0) - (1//1680)*(h^2)*a(7,2) - (1//5040)*(h^3)*a(8,0) + (1//180)*(h^3)*a(6,2) + (1//720)*(h^4)*a(7,0) - (1//24)*(h^4)*a(5,2) + (1//4)*(h^5)*a(4,2) - (1//120)*(h^5)*a(6,0) - (7//6)*(h^6)*a(3,2) + (1//24)*(h^6)*a(5,0) - (1//6)*(h^7)*a(4,0) + (4//1)*(h^7)*a(2,2) - 9(h^8)*a(1,2) + (1//2)*(h^8)*a(3,0) - (h^9)*a(2,0) + 10(h^9)*bs(1) + (h^10)*a(1,0)

Bs_coef[9, 1] = (1//362880)*b(10,1) - (1//40320)*h*b(9,1) + (1//5040)*(h^2)*b(8,1) - (1//720)*(h^3)*b(7,1) + (1//120)*(h^4)*b(6,1) - (1//24)*(h^5)*b(5,1) + (1//6)*(h^6)*b(4,1) - (1//2)*(h^7)*b(3,1) + (h^8)*b(2,1) - (h^9)*b(1,1)

## x^10 y^1

Bx_coef[10, 1] = (1//3628800)*b(12,0)

By_coef[10, 1] = -(1//3628800)*a(12,0) - (1//3628800)*a(10,2) - (1//3628800)*h*a(11,0) + (1//181440)*h*a(9,2) - (1//13440)*(h^2)*a(8,2) + (1//362880)*(h^2)*a(10,0) - (1//40320)*(h^3)*a(9,0) + (1//1260)*(h^3)*a(7,2) + (1//5040)*(h^4)*a(8,0) - (1//144)*(h^4)*a(6,2) - (1//720)*(h^5)*a(7,0) + (1//20)*(h^5)*a(5,2) - (7//24)*(h^6)*a(4,2) + (1//120)*(h^6)*a(6,0) + (4//3)*(h^7)*a(3,2) - (1//24)*(h^7)*a(5,0) + (1//6)*(h^8)*a(4,0) - (9//2)*(h^8)*a(2,2) + 10(h^9)*a(1,2) - (1//2)*(h^9)*a(3,0) + (h^10)*a(2,0) - 11(h^10)*bs(1) - (h^11)*a(1,0)

Bs_coef[10, 1] = (1//3628800)*b(11,1) - (1//362880)*h*b(10,1) + (1//40320)*(h^2)*b(9,1) - (1//5040)*(h^3)*b(8,1) + (1//720)*(h^4)*b(7,1) - (1//120)*(h^5)*b(6,1) + (1//24)*(h^6)*b(5,1) - (1//6)*(h^7)*b(4,1) + (1//2)*(h^8)*b(3,1) - (h^9)*b(2,1) + (h^10)*b(1,1)

## x^11 y^1

Bx_coef[11, 1] = (1//39916800)*b(13,0)

By_coef[11, 1] = -(1//39916800)*a(13,0) - (1//39916800)*a(11,2) - (1//39916800)*h*a(12,0) + (1//1814400)*h*a(10,2) + (1//3628800)*(h^2)*a(11,0) - (1//120960)*(h^2)*a(9,2) + (1//10080)*(h^3)*a(8,2) - (1//362880)*(h^3)*a(10,0) + (1//40320)*(h^4)*a(9,0) - (1//1008)*(h^4)*a(7,2) - (1//5040)*(h^5)*a(8,0) + (1//120)*(h^5)*a(6,2) + (1//720)*(h^6)*a(7,0) - (7//120)*(h^6)*a(5,2) + (1//3)*(h^7)*a(4,2) - (1//120)*(h^7)*a(6,0) - (3//2)*(h^8)*a(3,2) + (1//24)*(h^8)*a(5,0) - (1//6)*(h^9)*a(4,0) + (5//1)*(h^9)*a(2,2) - 11(h^10)*a(1,2) + (1//2)*(h^10)*a(3,0) - (h^11)*a(2,0) + 12(h^11)*bs(1) + (h^12)*a(1,0)

Bs_coef[11, 1] = (1//39916800)*b(12,1) - (1//3628800)*h*b(11,1) + (1//362880)*(h^2)*b(10,1) - (1//40320)*(h^3)*b(9,1) + (1//5040)*(h^4)*b(8,1) - (1//720)*(h^5)*b(7,1) + (1//120)*(h^6)*b(6,1) - (1//24)*(h^7)*b(5,1) + (1//6)*(h^8)*b(4,1) - (1//2)*(h^9)*b(3,1) + (h^10)*b(2,1) - (h^11)*b(1,1)

## x^0 y^2

Bx_coef[0, 2] = -(1//2)*a(1,2) - (1//2)*a(3,0) - (1//2)*h*a(2,0) + h*bs(1) + (1//2)*(h^2)*a(1,0)

By_coef[0, 2] = -(1//2)*b(3,0) - (1//2)*b(1,2) - (1//2)*h*b(2,0)

Bs_coef[0, 2] = -(1//2)*bs(2) - (1//2)*a(2,1) - (1//2)*h*a(1,1)

## x^1 y^2

Bx_coef[1, 2] = -(1//2)*a(4,0) - (1//2)*a(2,2) + 2h*a(1,2) - (1//2)*h*a(3,0) + (h^2)*a(2,0) - 3(h^2)*bs(1) - (h^3)*a(1,0)

By_coef[1, 2] = -(1//2)*b(2,2) - (1//2)*b(4,0) - (1//2)*h*b(3,0) + h*b(1,2) + (1//2)*(h^2)*b(2,0)

Bs_coef[1, 2] = -(1//2)*a(3,1) - (1//2)*a(1,3) + (3//2)*h*bs(2) + (h^2)*a(1,1)

## x^2 y^2

Bx_coef[2, 2] = -(1//4)*a(3,2) - (1//4)*a(5,0) - (1//4)*h*a(4,0) + (3//2)*h*a(2,2) - (9//2)*(h^2)*a(1,2) + (3//4)*(h^2)*a(3,0) - (3//2)*(h^3)*a(2,0) + (6//1)*(h^3)*bs(1) + (3//2)*(h^4)*a(1,0)

By_coef[2, 2] = -(1//4)*b(3,2) - (1//4)*b(5,0) + h*b(2,2) - (1//4)*h*b(4,0) + (1//2)*(h^2)*b(3,0) - (3//2)*(h^2)*b(1,2) - (1//2)*(h^3)*b(2,0)

Bs_coef[2, 2] = -(1//4)*a(2,3) - (1//4)*a(4,1) + (1//4)*h*a(3,1) + (3//2)*h*a(1,3) - (3//1)*(h^2)*bs(2) + (1//2)*(h^2)*a(2,1) - (3//2)*(h^3)*a(1,1)

## x^3 y^2

Bx_coef[3, 2] = -(1//12)*a(4,2) - (1//12)*a(6,0) + (2//3)*h*a(3,2) - (1//12)*h*a(5,0) + (1//3)*(h^2)*a(4,0) - (3//1)*(h^2)*a(2,2) + (8//1)*(h^3)*a(1,2) - (h^3)*a(3,0) + (2//1)*(h^4)*a(2,0) - (10//1)*(h^4)*bs(1) - (2//1)*(h^5)*a(1,0)

By_coef[3, 2] = -(1//12)*b(6,0) - (1//12)*b(4,2) + (1//2)*h*b(3,2) - (1//12)*h*b(5,0) - (3//2)*(h^2)*b(2,2) + (1//4)*(h^2)*b(4,0) - (1//2)*(h^3)*b(3,0) + (2//1)*(h^3)*b(1,2) + (1//2)*(h^4)*b(2,0)

Bs_coef[3, 2] = -(1//12)*a(5,1) - (1//12)*a(3,3) + (3//4)*h*a(2,3) + (1//6)*h*a(4,1) - (3//1)*(h^2)*a(1,3) + (5//1)*(h^3)*bs(2) - (h^3)*a(2,1) + (2//1)*(h^4)*a(1,1)

## x^4 y^2

